<main class="site-page-shell"><?=\Kovcheg\View::partial('site-sidebar',['active'=>'colleagues'])?><section class="people-page-060 people-page-080"><header class="settings-title"><div><h1>Коллеги</h1><p>Коллеги, подписчики, подписки и входящие заявки.</p></div></header><nav class="people-tabs"><a class="<?=$tab==='colleagues'?'active':''?>" href="<?=e(app_url('/colleagues'))?>">Коллеги</a><a class="<?=$tab==='followers'?'active':''?>" href="<?=e(app_url('/colleagues?tab=followers'))?>">Подписчики</a><a class="<?=$tab==='following'?'active':''?>" href="<?=e(app_url('/colleagues?tab=following'))?>">Подписки</a></nav>
